const { execFileSync } = require('child_process');
const fs = require('fs');

const results = $input.item.json.results || [];

// A single issue cannot duplicate itself
if (results.length < 2) {
  return [{json: {results: results}}];
}

const apiKey    = $env.ANTHROPIC_API_KEY;
const notionKey = $env.NOTION_API_KEY;
if (!apiKey || !notionKey) {
  return [{json: {results: results}}];
}

function txt(arr) { return (arr || []).map(t => t.plain_text).join(''); }

const issues = results.map(r => {
  const p = r.properties;
  return {
    pageId: r.id,
    num:    'ISSU-' + (p['ID']?.unique_id?.number ?? '?'),
    name:   txt(p['Name']?.title),
    comp:   p['Component']?.select?.name || '',
    type:   p['Type']?.select?.name || '',
    desc:   txt(p['Description']?.rich_text).substring(0, 200),
    root:   txt(p['Root Cause']?.rich_text).substring(0, 120)
  };
});

const listText = issues.map(i =>
  '- ' + i.num + ' [' + i.comp + ' / ' + i.type + ']: ' + i.name
  + (i.desc ? '\n    Desc: ' + i.desc : '')
  + (i.root ? '\n    Root: ' + i.root : '')
).join('\n');

const prompt =
  'Review these open bug/issue tickets and identify any DUPLICATES.\n\n'
  + 'OPEN ISSUES:\n' + listText + '\n\n'
  + 'Rules:\n'
  + '- Duplicates = same underlying problem (fixing one fixes the other)\n'
  + '- Different symptoms of the identical root cause = duplicate\n'
  + '- Keep the OLDEST ticket (lowest ISSU number), close the rest\n'
  + '- Different components with unrelated causes = NOT duplicates\n\n'
  + 'Respond with ONLY valid JSON, no markdown fences, no explanation:\n'
  + '{"duplicates":[{"keep":"ISSU-X","close":["ISSU-Y"],"reason":"one sentence"}]}\n'
  + 'If no duplicates: {"duplicates":[]}';

const tmpFile = '/tmp/bi_dedup_' + Date.now() + '.txt';
fs.writeFileSync(tmpFile, prompt, 'utf8');

let dupGroups = [];
try {
  const out = execFileSync(
    'node',
    ['/opt/claude-code/cli.js', '-p', '--output-format', 'text'],
    {
      input: fs.readFileSync(tmpFile),
      env: {ANTHROPIC_API_KEY: apiKey, HOME: '/home/node', PATH: '/usr/local/sbin:/usr/local/bin:/usr/sbin:/usr/bin:/sbin:/bin'},
      timeout: 60000,
      maxBuffer: 1 * 1024 * 1024,
      cwd: '/opt/agentic-sdlc'
    }
  );
  try { fs.unlinkSync(tmpFile); } catch (_) {}
  const text = out.toString('utf8').trim();
  const match = text.match(/\{[\s\S]*\}/);
  if (match) {
    dupGroups = JSON.parse(match[0]).duplicates || [];
  }
} catch (e) {
  try { fs.unlinkSync(tmpFile); } catch (_) {}
  // Dedup check failed — proceed with all issues unchanged
  return [{json: {results: results}}];
}

if (!dupGroups.length) {
  return [{json: {results: results}}];
}

// Build map: issue number → pageId
const numToPageId = {};
issues.forEach(i => { numToPageId[i.num] = i.pageId; });

// Collect pages to close and their notes
const toClose = {};
for (const grp of dupGroups) {
  for (const closeNum of (grp.close || [])) {
    const pageId = numToPageId[closeNum];
    if (pageId) {
      toClose[pageId] = ('DUPLICATE of ' + grp.keep + '. ' + (grp.reason || '')).substring(0, 500);
    }
  }
}

if (!Object.keys(toClose).length) {
  return [{json: {results: results}}];
}

// Mark each duplicate in Notion — use Wont Fix + Resolution note
for (const [pageId, note] of Object.entries(toClose)) {
  const body = JSON.stringify({
    properties: {
      Status: {select: {name: 'Wont Fix'}},
      Resolution: {rich_text: [{type: 'text', text: {content: note}}]}
    }
  });
  const bodyFile = '/tmp/notion_dup_' + pageId + '.json';
  fs.writeFileSync(bodyFile, body, 'utf8');
  try {
    execFileSync('curl', [
      '-s', '-X', 'PATCH',
      'https://api.notion.com/v1/pages/' + pageId,
      '-H', 'Content-Type: application/json',
      '-H', 'Notion-Version: 2022-06-28',
      '-H', 'Authorization: Bearer ' + notionKey,
      '-d', '@' + bodyFile
    ], {timeout: 10000});
  } catch (_) {}
  try { fs.unlinkSync(bodyFile); } catch (_) {}
}

// Return only the surviving (non-duplicate) issues
const closeSet = new Set(Object.keys(toClose));
return [{json: {results: results.filter(r => !closeSet.has(r.id))}}];

