const { execFileSync } = require('child_process');
const fs = require('fs');

const item = $input.item.json;
const fixerPrompt = item.fixer_prompt;
const issueNum    = item.issue_num    || '';
const issueName   = item.issue_name   || '';
const severity    = item.severity     || '';
const component   = item.component    || '';
const description = item.description  || '';
const rootCause   = item.root_cause   || '';
const reproSteps  = item.repro_steps  || '';
const issueType   = item.issue_type   || '';

if (!fixerPrompt) {
  return [{json: {exitCode: 1, stdout: '', stderr: 'ERROR: empty fixer_prompt', agentsUsed: 0, helpNeeded: false}}];
}

const apiKey = $env.ANTHROPIC_API_KEY;
if (!apiKey) {
  return [{json: {exitCode: 1, stdout: '', stderr: 'ERROR: ANTHROPIC_API_KEY not set', agentsUsed: 0, helpNeeded: false}}];
}

function runClaude(prompt, timeoutMs, label) {
  const tmpFile = '/tmp/bi_' + label + '_' + Date.now() + '.txt';
  fs.writeFileSync(tmpFile, prompt, 'utf8');
  try {
    const out = execFileSync(
      'node',
      ['/opt/claude-code/cli.js', '-p', '--output-format', 'text', '--add-dir', '/opt/agentic-sdlc'],
      {
        input: fs.readFileSync(tmpFile),
        env: {ANTHROPIC_API_KEY: apiKey, HOME: '/home/node', PATH: '/usr/local/sbin:/usr/local/bin:/usr/sbin:/usr/bin:/sbin:/bin'},
        timeout: timeoutMs,
        maxBuffer: 10 * 1024 * 1024,
        cwd: '/opt/agentic-sdlc'
      }
    );
    try { fs.unlinkSync(tmpFile); } catch (_) {}
    return {exitCode: 0, stdout: out.toString('utf8').trim(), stderr: '', timedOut: false};
  } catch (e) {
    try { fs.unlinkSync(tmpFile); } catch (_) {}
    return {
      exitCode: e.status || 1,
      stdout: e.stdout ? e.stdout.toString('utf8').trim() : '',
      stderr: e.stderr ? e.stderr.toString('utf8').trim() : e.message,
      timedOut: e.killed === true || e.signal === 'SIGTERM' || e.signal === 'SIGKILL'
    };
  }
}

// Decide if spawning a continuation helper is warranted after a timeout.
// Skip helper when: issue is a Question, fixer made no progress,
// or partial output indicates a blocking/waiting/linear situation.
function needsHelper(partial, type) {
  if (type === 'Question') return false;
  if (!partial || partial.trim().length < 50) return false;
  const blockPatterns = [
    /waiting for/i,
    /need(s)? to wait/i,
    /monitoring\s+(the\s+)?logs?/i,
    /manual\s+(review|intervention|action|setup)\s+required/i,
    /cannot\s+(automate|be\s+automated)/i,
    /requires?\s+(human|manual)/i,
    /waiting\s+for\s+(results?|output|completion|response)/i,
    /scheduled\s+(job|task|cron|sync)/i,
    /will\s+(run|execute|trigger)\s+(tonight|tomorrow|next|at\s+\d)/i
  ];
  return !blockPatterns.some(p => p.test(partial));
}

// --- Primary fixer agent (10 min) ---
const fixerResult = runClaude(fixerPrompt, 600000, 'fixer');

if (fixerResult.exitCode === 0) {
  return [{json: {exitCode: 0, stdout: fixerResult.stdout, stderr: '', agentsUsed: 1, helpNeeded: false}}];
}

// Hard failure (not a timeout) — helpers won't change outcome
if (!fixerResult.timedOut) {
  return [{json: {exitCode: fixerResult.exitCode, stdout: fixerResult.stdout, stderr: fixerResult.stderr, agentsUsed: 1, helpNeeded: false}}];
}

// Fixer timed out — check if a helper agent is warranted
const partial = fixerResult.stdout;
if (!needsHelper(partial, issueType)) {
  return [{json: {
    exitCode: 1,
    stdout: partial,
    stderr: 'Fixer timed out; helper not spawned (linear/waiting issue or insufficient progress detected).',
    agentsUsed: 1,
    helpNeeded: false
  }}];
}

// --- Spawn continuation helper agent ---
const helperPrompt =
  'You are a continuation agent for an Agentic SDLC infrastructure issue.\n'
  + 'A previous fix agent ran for 10 minutes but did not complete the task.\n'
  + 'Project root: /opt/agentic-sdlc on VPS 187.77.208.197. Read CLAUDE.md first.\n\n'
  + 'ORIGINAL ISSUE:\n'
  + 'ID: ' + issueNum + '\n'
  + 'Name: ' + issueName + '\n'
  + 'Severity: ' + severity + '\n'
  + 'Component: ' + component + '\n'
  + 'Description: ' + description + '\n'
  + 'Root Cause: ' + rootCause + '\n'
  + 'Reproduction Steps: ' + reproSteps + '\n\n'
  + 'PREVIOUS AGENT PARTIAL WORK (captured before 10-min timeout):\n'
  + (partial.substring(0, 800) || '(no output captured)') + '\n\n'
  + 'YOUR TASK:\n'
  + '1. Run: git -C /opt/agentic-sdlc status  — review any changes left by the previous agent\n'
  + '2. Assess current state vs. what still needs to be done\n'
  + '3. Complete the fix without undoing previous agent work\n'
  + '4. Follow the Completion Gate in CLAUDE.md\n'
  + '5. End with a RESOLUTION SUMMARY of what you completed\n\n'
  + 'This is a fresh isolated session. Complete the fix end-to-end.';

const helperResult = runClaude(helperPrompt, 600000, 'helper');

return [{json: {
  exitCode: helperResult.exitCode,
  stdout: helperResult.stdout,
  stderr: helperResult.timedOut
    ? 'TIMEOUT: fixer (10 min) and helper (10 min) both exceeded time limit. Manual intervention required.'
    : helperResult.stderr,
  agentsUsed: 2,
  helpNeeded: true,
  helperTimedOut: helperResult.timedOut
}}];

